function aggiornaChat(){$.ajaxQueue({url:baseUrl+"/virtual-assistant/messages/",cache:!1,async:!0,dataType:"html",success:function(content){$(".chat_messages").html(content)}})}
$(document).ready(function(){$("body").on("click",".send_request_to_va",function(e){e.preventDefault();var messaggio=$(".request_message").val();$.ajaxQueue({url:baseUrl+"/virtual-assistant/request/",async:!0,cache:!1,type:"POST",data:{messaggio:messaggio},dataType:"html",success:function(content){aggiornaChat()}})})})